const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const quotePremium = (step: QuoteStep): number => {
  const itemsBase = step.items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  return itemsBase + PROCESSING_FEE;
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

