import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / simplest cases ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums per main item type ---
  it("single plain sword → premium 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("single plain amulet → premium 65 G (60 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("single plain staff → premium 85 G (80 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 85 }] });
  });
  it("single plain potion → premium 45 G (40 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 45 }] });
  });

  // --- Components ---
  it("2 runes → 50 G base premium (+5 fee = 55)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 55 }] });
  });
  it("3 runes → 60 G base premium (block applies) (+5 fee = 65)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("4 runes → 100 G base premium (no block — block requires exactly 3) (+5 fee = 105)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" },
      ] }],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("7 runes → 175 G base premium (+5 fee = 180)", () => {
    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    expect(result).toEqual({ results: [{ premium: 180 }] });
  });

  // --- 'Alike' clarification ---
  it("2 runes + 1 moonstone → 75 G base premium (no block: different types) (+5 fee = 80)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "moonstone" },
      ] }],
    });
    expect(result).toEqual({ results: [{ premium: 80 }] });
  });
  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks) (+5 fee = 125)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
      ] }],
    });
    expect(result).toEqual({ results: [{ premium: 125 }] });
  });

  // --- Item-specific modifiers ---
  it("single cursed sword (steel, ench 3), newcomer first contract → 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "sword", material: "steel", enchantment: 3, cursed: true },
      ] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years → loyalty discount applies");

  // --- Modifier scope on multi-item policy ---
  it.todo("cursed sword + plain amulet → 210 G before further modifiers/fee (cursed surcharge on cursed item only)");

  // --- Rounding ---
  it.todo("premium calculation that yields 197.5 G → final premium 198 G (rounded up in MHPCO's favor)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
  it.todo("long-standing customer's second contract — cursed sword (steel, ench 7), 3 years → 160 G");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword damage 500 G → payout 400 G (full minus deductible)");
  it.todo("rune damage 200 G → payout 100 G (no special clause, deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");

  // --- Claim: enchantment vs dragon material ---
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50 % wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon-material: full minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50 % then deductible)");
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench applies, then deductible)");

  // --- Multiple items of same type ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G; dragon attack damages both with separate deductibles");
  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("policy: sword + amulet → insurance sum 1600 G (cap 3200 G)");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block affects premium only)");
  it.todo("sword, two successive claims of 1500 G each → first payout 1400 G, second 600 G; cap exhausted");

  // --- Payout rounding ---
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Edge case errors ---
  it.todo("quote with unknown item type → CLI exits non-zero with stderr error; no results on stdout");
  it.todo("claim references damage for item not in policy → CLI exits non-zero with stderr error");
  it.todo("claim has negative damage amount → CLI exits non-zero with stderr error");
});

