const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const groupByType = (items: Item[]): Item[][] => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return [...groups.values()];
};

const sumOfBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumFor(item), 0);

const basePremiumForGroup = (group: Item[]): number =>
  group.length === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : sumOfBasePremiums(group);

const totalBasePremium = (items: Item[]): number =>
  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);

const CURSE_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_RATE = 0.1;

const curseSurcharge = (items: Item[]): number =>
  items
    .filter((item) => item.cursed)
    .reduce((sum, item) => sum + basePremiumFor(item) * CURSE_SURCHARGE_RATE, 0);

const premiumFor = (items: Item[]): number => {
  const baseTotal = totalBasePremium(items);
  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_RATE;
  return Math.ceil(
    baseTotal + curseSurcharge(items) + firstInsuranceSurcharge + PROCESSING_FEE,
  );
};

const resultFor = (step: QuoteStep) => ({ premium: premiumFor(step.items) });

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map(resultFor) };
};

