const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Customer = { yearsWithMHPCO: number };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: Customer; steps: QuoteStep[] };

const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const groupByType = (items: Item[]): Item[][] => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return [...groups.values()];
};

const sumOfBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumFor(item), 0);

const basePremiumForGroup = (group: Item[]): number =>
  group.length === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : sumOfBasePremiums(group);

const totalBasePremium = (items: Item[]): number =>
  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);

const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_DISCOUNT_RATE = -0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

type Modifier<T> = { applies: (subject: T) => boolean; rate: number };

const sumApplicableRates = <T>(modifiers: Modifier<T>[], subject: T): number =>
  modifiers.reduce((sum, { applies, rate }) => sum + (applies(subject) ? rate : 0), 0);

const ITEM_SURCHARGES: Modifier<Item>[] = [
  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
];

const isFirstInsurance = (_customer: Customer): boolean => true;
const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const POLICY_MODIFIERS: Modifier<Customer>[] = [
  { applies: isFirstInsurance, rate: FIRST_INSURANCE_RATE },
  { applies: isLoyalCustomer, rate: LOYALTY_DISCOUNT_RATE },
];

const policyAdjustment = (baseTotal: number, customer: Customer): number =>
  baseTotal * sumApplicableRates(POLICY_MODIFIERS, customer);

const itemSurchargeFor = (item: Item): number =>
  basePremiumFor(item) * sumApplicableRates(ITEM_SURCHARGES, item);

const itemSurchargesTotal = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);

const premiumFor = (items: Item[], customer: Customer): number => {
  const baseTotal = totalBasePremium(items);
  return Math.ceil(
    baseTotal +
      itemSurchargesTotal(items) +
      policyAdjustment(baseTotal, customer) +
      PROCESSING_FEE,
  );
};

const resultFor = (step: QuoteStep, customer: Customer) => ({
  premium: premiumFor(step.items, customer),
});

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map((step) => resultFor(step, scenario.customer)) };
};

