const HIGH_DAMAGE_ENCHANTMENT_THRESHOLD = 8;
const HIGH_DAMAGE_ENCHANTMENT_RATE = 0.5;

const reimbursableAmount = (damage: Damage, item: Item): number =>
  (item.enchantment ?? 0) >= HIGH_DAMAGE_ENCHANTMENT_THRESHOLD
    ? damage.amount * HIGH_DAMAGE_ENCHANTMENT_RATE
    : damage.amount;

const payoutForDamage = (damage: Damage, item: Item): number =>
  reimbursableAmount(damage, item) - DEDUCTIBLE;

const claimResultFor = (
  step: ClaimStep,
  steps: Step[],
): { payout: number; remainingCap: number } => {
  const policy = steps[step.policy] as QuoteStep;
  const cap = insuranceSumFor(policy.items) * CAP_MULTIPLIER;
  const payout = sumBy(step.incident.damages, (damage) => {
    const item = policy.items.find((i) => i.type === damage.itemType)!;
    return payoutForDamage(damage, item);
  });
  return { payout, remainingCap: cap - payout };
};

