const countByType = <T extends { type?: string; itemType?: string }>(
  xs: T[],
  key: (x: T) => string,
): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const x of xs) counts.set(key(x), (counts.get(key(x)) ?? 0) + 1);
  return counts;
};

const validateDamageCounts = (step: ClaimStep, policy: QuoteStep): void => {
  const itemCounts = countByType(policy.items, (i) => i.type);
  const damageCounts = countByType(step.incident.damages, (d) => d.itemType);
  for (const [type, count] of damageCounts) {
    if (count > (itemCounts.get(type) ?? 0)) {
      throw new Error(`claim references more ${type} damages than the policy covers`);
    }
  }
};

const claimResultFor = (
  step: ClaimStep,
  policy: QuoteStep,
): { payout: number; remainingCap: number } => {
  validateDamageCounts(step, policy);
  const payout = sumBy(step.incident.damages, (damage) =>
    payoutForDamage(damage, policyItemFor(policy, damage)),
  );
  return { payout, remainingCap: capFor(policy) - payout };
};

